31.body:
路径 ：backend/plugins/auth-db/ 依赖 ：ducia-core、rusqlite、bcrypt、jsonwebtoken、chrono rusqlite — 操作 SQLite 数据库，存储用户注册信息 bcrypt — 密码哈希与验证，使用 DEFAULT_COST=12 jsonwebtoken — 签发与验证 JWT token（HS256 算法） chrono — 生成 UTC 时间戳（created_at 字段和 JWT 的 iat/exp claims） 原理 ：用户名+密码注册（bcrypt 哈希），登录返回 JWT（7天有效），Bearer Token 认证 配置 ：config/auth.json（jwt_secret 字段） 特点 ：多用户支持，持久化，支持注册/登录/获取用户信息 pub struct AuthDb { conn: Mutex<Connection>, jwt_secret: String,
} 数据库 Schema auth.db 在插件初始化时自动创建 users 表： CREATE TABLE IF NOT EXISTS users ( id TEXT PRIMARY KEY, -- UUID v4，用户唯一标识 username TEXT NOT NULL UNIQUE, -- 登录用户名，全局唯一 password TEXT NOT NULL, -- bcrypt 哈希后的密码 roles TEXT NOT NULL DEFAULT 'viewer', -- 逗号分隔的角色字符串 created_at INTEGER NOT NULL -- Unix 时间戳（秒），注册时间
); 列名 类型 约束 说明 id TEXT PRIMARY KEY UUID v4 字符串，由 uuid::Uuid::new_v4() 生成 username TEXT NOT NULL UNIQUE 注册时 trim 去除首尾空白，空字符串会被拒绝 password TEXT NOT NULL bcrypt 哈希值，使用 DEFAULT_COST（12）轮 roles TEXT NOT NULL, DEFAULT 'viewer' 逗号分隔的角色名，如 "viewer,editor"。注册时固定为 "viewer" created_at INTEGER NOT NULL chrono::Utc::now().timestamp() 生成的 Unix 秒级时间戳 注册流程 输入校验 ：检查 username.trim() 非空且 password.len() >= 4，不满足则返回错误 "username empty or password too short (min 4)" 生成 ID ：uuid::Uuid::new_v4().to_string() 生成全局唯一用户 ID 密码哈希 ：bcrypt::hash(&req.password, bcrypt::DEFAULT_COST) 对明文密码做 12 轮 bcrypt 哈希 写入数据库 ：执行 INSERT INTO users (id, username, password, roles, created_at) VALUES (?1,?2,?3,?4,?5)，roles 固定为 "viewer"，created_at 取当前 UTC 时间戳 返回结果 ：返回 UserInfo { id, username, roles: vec!["viewer"] } pub fn register(&self, req: &RegisterRequest) -> anyhow::Result<UserInfo> { if req.username.trim().is_empty() || req.password.len() < 4 { anyhow::bail!("username empty or password too short (min 4)"); } let conn = self.conn.lock().unwrap(); let id = uuid::Uuid::new_v4().to_string(); let hashed = bcrypt::hash(&req.password, bcrypt::DEFAULT_COST)?; let now = chrono::Utc::now().timestamp(); conn.execute( "INSERT INTO users (id, username, password, roles, created_at) VALUES (?1,?2,?3,?4,?5)", rusqlite::params![id, req.username.trim(), hashed, "viewer", now], )?; Ok(UserInfo { id, username: req.username.trim().to_string(), roles: vec!["viewer".into()] })
} 登录流程 查询用户 ：SELECT id, username, password, roles FROM users WHERE username = ?1，用户名不存在则返回 "invalid username or password"（不区分「用户不存在」和「密码错误」，防止用户枚举攻击） 密码验证 ：bcrypt::verify(&req.password, &hashed) 对比明文与 bcrypt 哈希 角色解析 ：将 DB 中的逗号分隔字符串 "viewer,editor" 拆分为 Vec<String>，过滤空串 构建 JWT Claims ：填充 sub（用户 ID）、username、roles、exp（当前时间 + 7天秒数）、iat（签发时间） 签发 Token ：jsonwebtoken::encode() 使用 HS256 算法和 jwt_secret 签名 返回结果 ：返回 AuthResponse { token, user: UserInfo { id, username, roles } } pub fn login(&self, req: &LoginRequest) -> anyhow::Result<AuthResponse> { let conn = self.conn.lock().unwrap(); let mut stmt = conn.prepare( "SELECT id, username, password, roles FROM users WHERE username = ?1" )?; let (id, username, hashed, roles_str): (String, String, String, String) = stmt.query_row([req.username.trim()], |row| { Ok((row.get(0)?, row.get(1)?, row.get(2)?, row.get(3)?)) }) .map_err(|_| anyhow::anyhow!("invalid username or password"))?; if !bcrypt::verify(&req.password, &hashed)? { anyhow::bail!("invalid username or password"); } let roles: Vec<String> = roles_str.split(',') .map(|s| s.trim().to_string()) .filter(|s| !s.is_empty()) .collect(); let now = chrono::Utc::now().timestamp() as usize; let claims = Claims { sub: id.clone(), username: username.clone(), roles: roles.clone(), exp: now + 86400 * 7, iat: now, }; let token = jsonwebtoken::encode( &jsonwebtoken::Header::default(), &claims, &jsonwebtoken::EncodingKey::from_secret(self.jwt_secret.as_bytes()), )?; Ok(AuthResponse { token, user: UserInfo { id, username, roles } })
} JWT Claims 结构 #[derive(Debug, Serialize, Deserialize)]
struct Claims { sub: String, // Subject — 用户 UUID（对应 users.id） username: String, // 用户名 roles: Vec<String>, // 角色列表，如 ["viewer", "editor"] exp: usize, // Expiration Time — 过期时间（Unix 秒），签发时设为 now + 604800（7天） iat: usize, // Issued At — 签发时间（Unix 秒）
} 字段 类型 说明 sub String Subject，用户唯一标识（UUID v4） username String 登录用户名 roles Vec<String> 角色列表，从 DB 的逗号分隔字符串解析而来 exp usize 过期时间，Unix 秒。登录时 = now + 86400 * 7；create_session 时 = now + 86400（1天） iat usize 签发时间，Unix 秒 Token 验证 authenticate() 方法实现 AuthPlugin trait 的请求认证入口： 提取 Token ：从请求头的 authorization 字段中提取 Bearer <token>（也支持 x-session-token 头作为备选） 空 Token 处理 ：token 为空字符串时直接返回 None（匿名用户） 解码 JWT ：调用 check_session() → verify_token()，使用 jsonwebtoken::decode::<Claims>() 解码，验证签名和过期时间 构建 Identity ：解码成功后将 claims.sub 作为 Identity.id、claims.roles 直接作为 Identity.roles、claims.username 存入 Identity.metadata async fn authenticate(&self, headers: &HashMap<String, String>) -> Option<Identity> { let token = headers .get("authorization") .and_then(|v| v.strip_prefix("Bearer ")) .or_else(|| headers.get("x-session-token").map(|s| s.as_str())) .unwrap_or(""); if token.is_empty() { return None; } self.check_session(token).await
} fn verify_token(&self, token: &str) -> Option<Identity> { let data = jsonwebtoken::decode::<Claims>( token, &jsonwebtoken::DecodingKey::from_secret(self.jwt_secret.as_bytes()), &jsonwebtoken::Validation::default(), ).ok()?; let claims = data.claims; let mut meta = HashMap::new(); meta.insert("username".into(), claims.username); Some(Identity { id: claims.sub, roles: claims.roles, permissions: vec![], metadata: meta, })
} 配置 config/auth.json 是认证配置入口。main.rs 检测该文件是否存在来决定使用 auth-db 还是 auth-simple： { "jwt_secret": "change-this-to-a-random-secret-key-in-production"
} jwt_secret 为 可选字段 （Option<String>）。如果未提供，插件自动用 uuid::Uuid::new_v4() 生成一个随机密钥（进程生命周期内不变，重启后会变更——已签发的 JWT 全部失效） 建议生产环境手动设置一个强随机字符串，例如 openssl rand -base64 64 生成 密码约束 最小长度 ：req.password.len() < 4 时拒绝注册，返回 400 错误 哈希成本 ：bcrypt::DEFAULT_COST（常量值 12），在安全性与注册/登录延迟之间取平衡 用户名空字符串也会被拒绝（username.trim().is_empty() 检查） 与 roles.json 的关系 注册角色 ：新注册用户的 roles 字段固定为 "viewer"，对应 config/roles.json 中定义的 viewer 角色（拥有 doc:read 权限）。管理员可通过直接修改 SQLite 数据库将用户的 roles 字段改为 "viewer,editor" 等形式来提升权限（尚无管理 UI） 角色存储格式 ：users.roles 是逗号分隔的字符串（如 "viewer,editor,admin"），登录时通过 split(',') 解析为 Vec<String>，空字符串被过滤 Identity 构建 ：JWT 中携带角色列表 → verify_token() 将其填入 Identity.roles；permissions 字段初始为空 vec![]，后续由 RoleConfig::resolve_permissions() 展开继承链并注入实际权限字符串 API 端点 以下端点注册在 main.rs 的路由表中（路径为 handle_403 模式，见 鉴权模型 ）： 方法 路径 Handler 说明 POST /api/auth/register handlers::auth_handler::register 注册新用户，body: {"username":"...","password":"..."} POST /api/auth/login handlers::auth_handler::login 登录，返回 JWT token + 用户信息 GET /api/auth/me handlers::auth_handler::me 获取当前用户信息，需要 Authorization: Bearer <token> 头 register 成功返回 200 + {"success":true,"data":{...}}，失败返回 400。login 和 me 认证失败返回 401。 curl 示例 注册新用户： curl -s -X POST http://127.0.0.1:3001/api/auth/register \ -H "Content-Type: application/json" \ -d '{"username":"alice","password":"secret123"}'
# 响应：{"success":true,"data":{"id":"...","username":"alice","roles":["viewer"]}} 登录获取 Token： curl -s -X POST http://127.0.0.1:3001/api/auth/login \ -H "Content-Type: application/json" \ -d '{"username":"alice","password":"secret123"}'
# 响应：{"success":true,"data":{"token":"eyJhbG...","user":{...}}} 用 Token 获取当前用户信息： curl -s http://127.0.0.1:3001/api/auth/me \ -H "Authorization: Bearer eyJhbG..."
# 响应：{"success":true,"data":{"id":"...","roles":["viewer"],"username":"alice"}} 安全提示 更换 jwt_secret ：生产部署必须在 config/auth.json 中设置一个强随机密钥（例如 openssl rand -base64 64），默认值和自动生成的 UUID 都不安全 密码强度 ：bcrypt 的 12 轮哈希能抵抗暴力破解，但用户仍应使用足够复杂的密码。框架目前仅要求最低 4 字符，无复杂度策略 JWT 无状态 ：JWT 在签发后无法服务端撤销（destroy_session 直接返回 Ok(())）。这意味着即使用户"登出"，已签发的 Token 在过期前仍然有效。如果场景要求即时吊销，需在 auth-db 之上加一层 Token 黑名单机制 错误信息一致 ：登录失败时始终返回 "invalid username or password"，不区分用户不存在和密码错误，防止用户名枚举

